1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	};
19	
20	const quotePremium = (step: QuoteStep): number => {
21	  const itemsPremium = step.items.reduce((sum, item) => {
22	    const basePremium = BASE_PREMIUMS[item.type];
23	    return sum + basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
24	  }, 0);
25	  const total = itemsPremium + PROCESSING_FEE;
26	  return Math.ceil(Number(total.toFixed(6)));
27	};
28	
29	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
30	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
31	};
